import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

// A 1 kHz square from the host means a write every 500 us. USB serial round
// trips are typically 1 to 2 ms, so this will not actually hit 1 kHz.
// For a clean square wave use a hardware timer on the device side instead
// (firmware module or PWM at 50 percent duty).

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const OUT_PIN = 8
await device.pin(OUT_PIN).mode('output')

let level = 0
while (true) {
  level ^= 1
  await device.pin(OUT_PIN).write(level)
}
