import { ConduytDevice } from 'conduyt-js'
import { WebSerialTransport } from 'conduyt-js/transports/web-serial'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const port = await navigator.serial.requestPort()
  const device = await ConduytDevice.connect(new WebSerialTransport({ port, baudRate: 115200 }))

  const i2c = device.i2c()
  const BME = 0x76

  // Force CTRL_HUM=1, CTRL_MEAS=0x27 (T x1, P x1, normal mode), CONFIG=0xA0.
  await i2c.write(BME, new Uint8Array([0xF2, 0x01]))
  await i2c.write(BME, new Uint8Array([0xF4, 0x27]))
  await i2c.write(BME, new Uint8Array([0xF5, 0xA0]))

  setInterval(async () => {
    const raw = await i2c.readReg(BME, 0xF7, 8)
    // Calibration unpacking is omitted; treat raw values as opaque sample bytes.
    console.log('bme raw', Array.from(raw))
  }, 1000)
})
