import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytNeoPixel } from 'conduyt-js/modules/neopixel'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const strip = new ConduytNeoPixel(device)
await strip.begin(6, 30)
await strip.setBrightness(40)

function wheel(pos: number): [number, number, number] {
  pos = (255 - pos) & 255
  if (pos < 85)  return [255 - pos * 3, 0, pos * 3]
  if (pos < 170) { pos -= 85;  return [0, pos * 3, 255 - pos * 3] }
  pos -= 170;     return [pos * 3, 255 - pos * 3, 0]
}

let j = 0
while (true) {
  for (let i = 0; i < 30; i++) {
    const [r, g, b] = wheel(((i * 256 / 30) + j) & 255)
    await strip.setPixel(i, r, g, b)
  }
  await strip.show()
  j = (j + 1) & 255
  await new Promise(r => setTimeout(r, 20))
}
