import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const BUZZER_PIN = 8
await device.pin(BUZZER_PIN).mode('pwm')

const FREQS = [262, 294, 330, 349, 392]

for (const _f of FREQS) {
  // Pin proxies on most boards expose a fixed PWM carrier; pitch shaping
  // belongs in firmware. Here we just gate on/off with a 50 percent duty.
  await device.pin(BUZZER_PIN).write(128)
  await new Promise(r => setTimeout(r, 300))
  await device.pin(BUZZER_PIN).write(0)
  await new Promise(r => setTimeout(r, 50))
}
