import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

// HC-SR04 timing is too tight for host-side pulseIn over a serial link.
// The firmware should run a dedicated module that returns distance in
// centimeters; on the host we just call read() on the module proxy.

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const sonar = device.module('hcsr04')
await sonar.send('begin', { trig: 9, echo: 10 })

setInterval(async () => {
  const { cm } = await sonar.send('read')
  console.log('cm', cm.toFixed(1))
}, 200)
